// Разбираем pendingOptionsJson из таблицы задач.
// Определяем: есть ли готовый ответ для отправки в OpenCode API (hasAnswerPayload)
//              или вопрос ещё нужно доставить пользователю (shouldSendQuestion).

const input = $('Разбираем входные данные').item.json
let pendingMeta = {}
try {
  pendingMeta = JSON.parse(String(input.pendingOptionsJson || '{}'))
} catch {}

const requestId = String(pendingMeta.requestId || '').trim()
const deliveredAt = String(pendingMeta.deliveredAt || '').trim()
const interactionType = Array.isArray(pendingMeta.questions)
  ? 'question'
  : String(pendingMeta.type || '').trim()

const answers = Array.isArray(pendingMeta.answers) ? pendingMeta.answers : []
const rejectRequested = pendingMeta.rejectRequested === true
const permissionReply = String(pendingMeta.reply || '').trim()
const permissionMessage = String(pendingMeta.message || '').trim()

// Готов ли ответ для отправки в OpenCode?
//   question:   есть requestId И (отклонён ИЛИ есть выбранные варианты)
//   permission: есть requestId И выбран тип ответа (once/always/reject)
//   иначе:      false (неизвестный тип интеракции — не ломаемся)
const hasAnswerPayload =
  interactionType === 'question'
    ? Boolean(requestId) && (rejectRequested || answers.length > 0)
    : interactionType === 'permission'
      ? Boolean(requestId) && Boolean(permissionReply)
      : false

// Нужно ли отправить вопрос пользователю? (ещё не доставлен и нет готового ответа)
const shouldSendQuestion =
  Boolean(requestId) &&
  !hasAnswerPayload &&
  !deliveredAt &&
  String(input.pendingQuestion || '').trim()

return {
  json: {
    taskKey: input.taskKey,
    sessionId: input.sessionId,
    chatId: input.chatId,
    hasAnswerPayload,
    shouldSendQuestion,
    interactionType,
    requestId,
    requestAction: rejectRequested ? 'reject' : 'reply',
    answers,
    permissionReply,
    permissionMessage,
  },
}

// Ищем permission-запрос от OpenCode для текущей сессии.
// Если найден — форматируем читаемый текст с паттернами и вариантами ответа.
// Если не найден — возвращаем hasInteraction: false (нода ниже уйдёт в ветку «нет прав»).

const input = $('Разбираем входные данные').item.json
const rawItems = $('Получаем запросы прав').all().map((item) => item.json)
const requests = rawItems
  .flatMap((item) => Array.isArray(item) ? item : [item])
  .filter((item) => item && !item.error)

const request = requests.find(
  (item) => String(item.sessionID || '').trim() === input.sessionId
)

if (!request) return { json: { hasInteraction: false } }

// Безопасно извлекаем поля ответа API (может быть null, не-массив и т.д.)
const patterns = Array.isArray(request.patterns) ? request.patterns : []
const alwaysPatterns = Array.isArray(request.always) ? request.always : []
const metadata = request.metadata && typeof request.metadata === 'object' ? request.metadata : {}

// Форматируем паттерны в маркированный список
const patternLines = patterns.length > 0
  ? patterns.filter(Boolean).map((pattern) => `- ${String(pattern).trim()}`).join('\n')
  : '- (паттерн не указан)'

const alwaysLines = alwaysPatterns.length > 0
  ? alwaysPatterns.filter(Boolean).map((pattern) => `- ${String(pattern).trim()}`).join('\n')
  : '- (нет рекомендуемых паттернов)'

const metadataText = Object.keys(metadata).length > 0
  ? JSON.stringify(metadata, null, 2)
  : ''

// Собираем сообщение для отправки пользователю в Telegram
const questionText = [
  `OpenCode запрашивает разрешение по задаче ${input.taskKey || 'неизвестно'}.`,
  String(request.title || 'Требуется подтверждение действия.').trim(),
  '',
  `Тип permission: ${String(request.permission || 'unknown').trim()}`,
  'Запрошенные паттерны:',
  patternLines,
  '',
  'Если выбрать always, будут разрешены паттерны:',
  alwaysLines,
  metadataText ? `\nДополнительные данные:\n${metadataText}` : '',
  '',
  'Ответьте одним из вариантов:',
  '1. once — разрешить один раз',
  '2. always — разрешить всегда для предложенных паттернов',
  '3. reject — отклонить',
].filter(Boolean).join('\n').trim()

return {
  json: {
    hasInteraction: true,
    interactionType: 'permission',
    pendingQuestionText: questionText,
    // Сохраняем контекст интеракции: requestId нужен для ответа в OpenCode API
    pendingOptionsJson: JSON.stringify({
      type: 'permission',
      requestId: String(request.id || '').trim(),
      reply: '',
      message: '',
    }),
  },
}

// Ищем question-запрос от OpenCode для текущей сессии.
// Если найден — форматируем читаемый текст с вариантами ответа.
// Каждый вопрос: header, body, варианты (с нумерацией для ответа пользователя).

const input = $('Разбираем входные данные').item.json
const rawItems = $('Получаем ожидающие вопросы').all().map((item) => item.json)
const requests = rawItems
  .flatMap((item) => Array.isArray(item) ? item : [item])
  .filter((item) => item && !item.error)

const request = requests.find(
  (item) => String(item.sessionID || '').trim() === input.sessionId
)

if (!request) return { json: { hasInteraction: false } }

const questions = Array.isArray(request.questions) ? request.questions : []

// Форматируем каждый вопрос в текстовый блок
const blocks = questions.map((question, index) => {
  const lines = []
  lines.push(`${index + 1}. ${String(question.header || '').trim()}`)
  const body = String(question.question || '').trim()
  if (body) lines.push(body)

  const options = Array.isArray(question.options) ? question.options : []
  if (options.length > 0) {
    lines.push('')
    options.forEach((option, i) => {
      lines.push(`${i + 1}. ${String(option.label || '').trim()}`)
    })
  }

  lines.push('')
  lines.push(question.multiple ? 'Можно выбрать несколько вариантов.' : 'Выберите один вариант.')
  return lines.join('\n').trim()
})

const questionText = [
  `OpenCode ждёт уточнение по задаче ${input.taskKey || 'неизвестно'}.`,
  '',
  blocks.join('\n\n'),
  '',
  'Для отклонения отправьте /reject или task_key: /reject.',
].join('\n').trim()

return {
  json: {
    hasInteraction: true,
    interactionType: 'question',
    pendingQuestionText: questionText,
    // Сохраняем контекст: санированные копии вопросов + requestId для ответа в API
    pendingOptionsJson: JSON.stringify({
      requestId: String(request.id || '').trim(),
      questions: questions.map((question) => ({
        question: String(question.question || '').trim(),
        header: String(question.header || '').trim(),
        multiple: Boolean(question.multiple),
        custom: question.custom !== false,
        options: (Array.isArray(question.options) ? question.options : []).map((option) => ({
          label: String(option.label || '').trim(),
          description: String(option.description || '').trim(),
        })),
      })),
      answers: null,
      rejectRequested: false,
    }),
  },
}

// Универсальный сборщик: берём данные из любой ветки интеракции (permission или question)
// и добавляем контекст задачи.

const item = $input.item.json
const context = $('Разбираем входные данные').item.json

return {
  json: {
    hasInteraction: Boolean(item.hasInteraction),
    interactionType: String(item.interactionType || '').trim(),
    pendingQuestionText: String(item.pendingQuestionText || '').trim(),
    pendingOptionsJson: String(item.pendingOptionsJson || '[]'),
    taskKey: item.taskKey || context.taskKey,
    sessionId: item.sessionId || context.sessionId,
    chatId: item.chatId || context.chatId,
  },
}

// Определяем итоговый resultType по приоритету:
//   abort > pending_sent > interaction_processed > interaction_found > no_action
// taskKey/sessionId/chatId берём из data, с fallback на контекст вызова —
// иначе ветка «нет вопроса» потеряет все три поля и сломает paired-item цепочку диспетчера.

const data = $input.item.json
const context = $('Разбираем входные данные').item.json

const resultType = data.taskCancelled ? 'abort'
  : data.questionSent ? 'pending_sent'
  : data.hasAnswerPayload ? 'interaction_processed'
  : data.hasInteraction ? 'interaction_found'
  : 'no_action'

return {
  json: {
    taskKey: data.taskKey || context.taskKey || '',
    sessionId: data.sessionId || context.sessionId || '',
    chatId: data.chatId || context.chatId || '',
    resultType,
    interactionType: data.interactionType || '',
    hasInteraction: data.hasInteraction || false,
    questionSent: data.questionSent || false,
    taskCancelled: data.taskCancelled || false,
    error: data.replyError || data.error || '',
    pendingQuestionText: data.pendingQuestionText || '',
    pendingOptionsJson: data.pendingOptionsJson || '',
  },
}

// Маркируем: вопрос отправлен пользователю в Telegram.

const context = $('Разбираем входные данные').item.json
return { json: { taskKey: context.taskKey, sessionId: context.sessionId, chatId: context.chatId, resultType: 'pending_sent', questionSent: true } }

// Маркируем: задача отменена (abort).

const context = $('Разбираем входные данные').item.json
return { json: { taskKey: context.taskKey, sessionId: context.sessionId, chatId: context.chatId, resultType: 'abort', taskCancelled: true } }

// После отправки ответа в OpenCode API собираем итог: ошибка или успех.
// Очистка от HTML-тегов: Telegram-нода по умолчанию шлёт parse_mode=HTML.

const stripHtml = (str) => String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').trim()

const httpResult = $input.item.json
const answer = $('Готовим ответ пользователю').item.json
const context = $('Разбираем входные данные').item.json

return {
  json: {
    taskKey: answer.taskKey || context.taskKey,
    sessionId: answer.sessionId || context.sessionId,
    chatId: answer.chatId || context.chatId,
    resultType: 'interaction_processed',
    interactionType: answer.interactionType,
    requestAction: answer.requestAction,
    hasInteraction: true,
    hasAnswerPayload: true,
    // Ошибка: либо от n8n ($input.item.error), либо из тела ответа API
    replyError: stripHtml($input.item.error?.message || (httpResult.error ? String(httpResult.error.message || httpResult.error) : '')),
  },
}
